"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/components/AuthProvider";

export default function LoginPage() {
  const [key, setKey] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const { login, apiKey } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (apiKey) router.push("/browse");
  }, [apiKey, router]);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!key.trim()) return;

    setLoading(true);
    setError("");

    try {
      await login(key.trim());
      router.push("/browse");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Invalid API key");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center px-4">
      <div className="w-full max-w-sm">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold tracking-tight">SLATE</h1>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <input
              type="password"
              value={key}
              onChange={(e) => setKey(e.target.value)}
              placeholder="Enter your TorBox API key"
              className="w-full rounded-lg border px-4 py-3 font-mono text-sm outline-none transition-colors"
              style={{
                background: "var(--input-bg)",
                borderColor: error ? "rgba(239,68,68,0.5)" : "var(--input-border)",
                color: "var(--fg)",
              }}
              onFocus={(e) => {
                e.target.style.background = "var(--input-bg-focus)";
                if (!error) e.target.style.borderColor = "var(--input-border-focus)";
              }}
              onBlur={(e) => {
                e.target.style.background = "var(--input-bg)";
                if (!error) e.target.style.borderColor = "var(--input-border)";
              }}
              autoFocus
            />
            {error && <p className="mt-2 text-xs text-red-400">{error}</p>}
          </div>

          <button
            type="submit"
            disabled={loading || !key.trim()}
            className="w-full rounded-lg py-3 text-sm font-medium transition-opacity hover:opacity-90 disabled:opacity-40"
            style={{ background: "var(--btn-primary-bg)", color: "var(--btn-primary-fg)" }}
          >
            {loading ? (
              <span className="inline-flex items-center gap-2">
                <span className="h-4 w-4 animate-spin rounded-full border-2" style={{ borderColor: "var(--btn-primary-fg)", borderTopColor: "transparent", opacity: 0.6 }} />
                Connecting...
              </span>
            ) : (
              "Connect"
            )}
          </button>
        </form>

        <p className="mt-6 text-center text-xs" style={{ color: "var(--text-hint)" }}>
          Your API key is stored locally and never sent to third parties.
        </p>
      </div>
    </div>
  );
}
